return ['project-id-version'=>'undefined','mime-version'=>'1.0','content-type'=>'text/plain; charset=UTF-8','content-transfer-encoding'=>'8bit','last-translator'=>'','pot-creation-date'=>'2026-06-19 15:47+0000','x-poedit-basepath'=>'..','x-poedit-keywordslist'=>'__;_e;_ex:1,2c;_n:1,2;_n_noop:1,2;_nx:1,2,4c;_nx_noop:1,2,3c;_x:1,2c;esc_attr__;esc_attr_e;esc_attr_x:1,2c;esc_html__;esc_html_e;esc_html_x:1,2c','x-poedit-searchpath-0'=>'.','x-poedit-searchpathexcluded-0'=>'*.js','x-poedit-sourcecharset'=>'UTF-8','plural-forms'=>'nplurals=2; plural=n != 1;','report-msgid-bugs-to'=>'','po-revision-date'=>'2026-07-08 14:08+0000','language-team'=>'Español de Colombia','language'=>'es_CO','x-generator'=>'Loco https://localise.biz/','x-loco-version'=>'2.8.5; wp-7.0; php-8.2.12','messages'=>['Activate WooCommerce'=>'Activar WooCommerce','Install WooCommerce'=>'Instalar WooCommerce','See WooCommerce'=>'Ver WooCommerce','The Mercado Pago module needs an active version of %s in order to work!'=>'¡El módulo de Mercado Pago necesita una versión activa de %s para funcionar!','Mercado Pago payments for WooCommerce requires PHP version 7.4 or later. Please update your PHP version.'=>'Los pagos con Mercado Pago para WooCommerce requieren la versión 7.4 o posterior de PHP. Actualiza tu versión de PHP.','Mercado Pago Error: PHP Extension CURL is not installed.'=>'Error de Mercado Pago: la extensión CURL de PHP no está instalada.','Mercado Pago Error: PHP Extension GD is not installed. Installation of GD extension is required to send QR Code Pix by email.'=>'Error de Mercado Pago: La extensión GD de PHP no está instalada. Es necesario instalar la extensión GD para enviar códigos QR por correo electrónico.','Please note that to receive payments via Pix at our checkout, you must have a Pix key registered in your Mercado Pago account.'=>'Ten en cuenta que, para recibir pagos a través de Pix en nuestra pasarela de pago, debes tener una clave Pix registrada en tu cuenta de Mercado Pago.','Register your Pix key at Mercado Pago.'=>'Registra tu clave Pix en Mercado Pago.','%s, help us improve the experience we offer'=>'%s, ayúdanos a mejorar la experiencia que ofrecemos','Share your opinion with us so that we improve our product and offer the best payment solution.'=>'Comparte tu opinión con nosotros para que podamos mejorar nuestro producto y ofrecerte la mejor solución de pago.','Rate the plugin'=>'Valora el complemento','Enable payments via Mercado Pago account'=>'Habilitar los pagos a través de la cuenta de Mercado Pago','When you enable this function, your customers pay faster using their Mercado Pago accounts.</br>The approval rate of these payments in your store can be 25% higher compared to other payment methods.'=>'Al activar esta función, tus clientes podrán pagar más rápido utilizando sus cuentas de Mercado Pago.</br>La tasa de aprobación de estos pagos en tu tienda puede ser un 25 % superior en comparación con otros métodos de pago.','Activate'=>'Activar','Our plugin does not support the language you\'ve chosen, so we\'ve switched it to the English default. If you prefer, you can also select Spanish or Portuguese (Brazilian).'=>'Nuestro complemento no es compatible con el idioma que has elegido, por lo que lo hemos cambiado al inglés, que es el idioma predeterminado. Si lo prefieres, también puedes seleccionar el español o el portugués (de Brasil).','You activated Mercado Pago’s plug-in'=>'Has activado el complemento de Mercado Pago','Follow the instructions below to integrate your store with Mercado Pago and start to sell.'=>'Sigue las instrucciones que aparecen a continuación para integrar tu tienda con Mercado Pago y empezar a vender.','Set plugin'=>'Configurar el complemento','Payment methods'=>'Formas de pago','Plugin manual'=>'Manual del complemento','Cancel order'=>'Cancelar pedido','Mercado Pago commission:'=>'Comisión de Mercado Pago:','Represents the commission configured on plugin settings.'=>'Representa la comisión configurada en los ajustes del complemento.','Mercado Pago discount:'=>'Descuento de Mercado Pago:','Represents the discount configured on plugin settings.'=>'Representa el descuento configurado en los ajustes del complemento.','Represents the installment fee charged by Mercado Pago.'=>'Corresponde a la comisión por pago a plazos que cobra Mercado Pago.','Mercado Pago Installment Fee:'=>'Comisión por pago a plazos de Mercado Pago:','Represents the total purchase plus the installment fee charged by Mercado Pago.'=>'Corresponde al importe total de la compra más la comisión por pago a plazos que cobra Mercado Pago.','Mercado Pago Total:'=>'Total de Mercado Pago:','Accept'=>'Aceptar','payments'=>'pagos','safely'=>'de forma segura','with'=>'con','Mercado Pago'=>'Mercado Pago','Choose'=>'Elige','when you want to receive the money'=>'cuando quieras recibir el dinero','from your sales and if you want to offer'=>'de tus ventas y si quieres ofrecer','admin settings descriptioninterest-free installments'=>'pagos a plazos sin intereses','to your clients.'=>'a tus clientes.','SSL'=>'SSL','Curl'=>'Curl','GD Extensions'=>'Extensiones GD','Technical requirements'=>'Requisitos técnicos','Collections and installments'=>'Cobros y pagos a plazos','More information'=>'Más información','Implementation responsible for transmitting data to Mercado Pago in a secure and encrypted way.'=>'Implementación encargada de transmitir datos a Mercado Pago de forma segura y cifrada.','It is an extension responsible for making payments via requests from the plugin to Mercado Pago.'=>'Se trata de una extensión encargada de realizar pagos a través de las solicitudes que envía el complemento a Mercado Pago.','These extensions are responsible for the implementation and operation of Pix in your store.'=>'Estas extensiones se encargan de la implementación y el funcionamiento de Pix en tu tienda.','Check our documentation to learn more about integrating our plug-in.'=>'Consulta nuestra documentación para obtener más información sobre cómo integrar nuestro complemento.','Set deadlines and fees'=>'Establecer plazos y tarifas','Go to documentation'=>'Ir a la documentación','Public Key'=>'Clave pública','Access Token'=>'Token de acceso','Close'=>'Cerrar','1. Link your store to a Mercado Pago account'=>'1. Vincula tu tienda a una cuenta de Mercado Pago','Linked account'=>'Cuenta vinculada','For more information, check the'=>'Para obtener más información, consulta la','Production credentials'=>'Experiencia en producción','Test credentials'=>'Comprobar credenciales','To start selling, '=>'Para empezar a vender, ','in the fields below. If you don’t have credentials yet, you’ll have to create them from this link.'=>'en los campos que aparecen a continuación. Si aún no dispones de credenciales, tendrás que crearlas desde este enlace.','Enable Mercado Pago checkouts for test purchases in the store.'=>'Activa el proceso de pago con Mercado Pago para las compras de prueba en la tienda.','Enable Mercado Pago checkouts to receive real payments in the store.'=>'Activa la opción de pago con Mercado Pago para recibir pagos reales en la tienda.','Paste the key here'=>'Pega aquí la clave','Show Access Token'=>'Mostrar token de acceso','Hide Access Token'=>'Ocultar el token de acceso','Continue'=>'Continuar','You have to enter your production credentials to start selling with Mercado Pago.'=>'Tienes que introducir tus credenciales de producción para empezar a vender con Mercado Pago.','Enter credentials'=>'Introduce tus datos de acceso','Activate your credentials to be able to sell'=>'Activa tus credenciales para poder vender','Credentials are codes that you must enter to enable sales. Go below on Activate Credentials. On the next screen, use again the Activate Credentials button and fill in the fields with the requested information.'=>'Las credenciales son códigos que debes introducir para habilitar las ventas. Desplázate hacia abajo hasta «Activar credenciales». En la siguiente pantalla, vuelve a pulsar el botón «Activar credenciales» y rellena los campos con la información solicitada.','Activate credentials'=>'Activar credenciales','copy and paste your production credentials '=>'Copia y pega tus credenciales de producción ','Your WooCommerce store can’t receive payments'=>'Tu tienda de WooCommerce no puede recibir pagos','To start selling again, update your store’s link to Mercado Pago.'=>'Para volver a vender, actualiza el enlace de tu tienda a Mercado Pago.','Update link'=>'Enlace de actualización','Add the URL to receive payments notifications.'=>'Añade la URL para recibir notificaciones de pagos.','Find out more information in the'=>'Para obtener más información, consulta el','guides'=>'guías','If you are a Mercado Pago Certified Partner, make sure to add your integrator_id.'=>'Si eres socio certificado de Mercado Pago, asegúrate de añadir tu «integrator_id».','If you do not have the code, please'=>'Si no tienes el código, por favor','request it now'=>'solicítalo ahora','2. Customize your business’ information'=>'2. Personaliza la información de tu empresa','Your store information'=>'Datos de tu tienda','Advanced integration options (optional)'=>'Opciones de integración avanzadas (opcional)','Debug and Log Mode'=>'Modo de depuración y registro','Fill out the following details to have a better experience and offer your customers more information.'=>'Rellena los siguientes datos para disfrutar de una mejor experiencia y ofrecer más información a tus clientes.','Name of your store in your client\'s invoice'=>'Nombre de tu tienda en la factura de tu cliente','Identification in Activities of Mercado Pago'=>'Identificación en las actividades de Mercado Pago','For further integration of your store with Mercado Pago (IPN, Certified Partners, Debug Mode)'=>'Para una mayor integración de tu tienda con Mercado Pago (IPN, socios certificados, modo de depuración)','Store category'=>'Categoría de la tienda','URL for IPN'=>'URL para IPN','Integrator ID'=>'ID del integrador','We record your store\'s actions in order to provide a better assistance.'=>'Registramos las acciones de tu tienda con el fin de ofrecerte una mejor atención.','Ex: Mary\'s Store'=>'Ej.: La tienda de Mary','Ex: Mary Store'=>'Ej.: Tienda Mary','Select'=>'Seleccionar','Ex: https://examples.com/my-custom-ipn-url'=>'Ej.: https://examples.com/my-custom-ipn-url','Add plugin default params'=>'Añadir los parámetros predeterminados del complemento','Ex: 14987126498'=>'Ej.: 14987126498','Show advanced options'=>'Mostrar opciones avanzadas','Hide advanced options'=>'Ocultar opciones avanzadas','Save and continue'=>'Guardar y continuar','If this field is empty, the purchase will be identified as Mercado Pago.'=>'Si este campo está vacío, la compra se identificará como «Mercado Pago».','In Activities, you will view this term before the order number'=>'En «Actividades», verás este término antes del número de pedido.','Select "Other categories" if you do not find the appropriate category.'=>'Selecciona «Otras categorías» si no encuentras la categoría adecuada.','request it now.'=>'Solicítalo ahora.','Order tracking'=>'Seguimiento de pedidos','Keep your Mercado Pago orders updated by selecting the desired frequency. We recommend enabling this option only in the event of automatic order update failures.'=>'Mantén actualizados tus pedidos de Mercado Pago seleccionando la frecuencia que desees. Te recomendamos que actives esta opción únicamente en caso de que se produzcan fallos en la actualización automática de los pedidos.','Disable'=>'Desactivar','Every 5 minutes'=>'Cada 5 minutos','Every 10 minutes'=>'Cada 10 minutos','Every 15 minutes'=>'Cada 15 minutos','Every 30 minutes'=>'Cada 30 minutos','Every 1 hour'=>'Cada hora','3. Activate and set up payment methods'=>'3. Activar y configurar los métodos de pago','Select the payment method you want to appear in your store to activate and set it up.'=>'Selecciona el método de pago que quieras que aparezca en tu tienda para activarlo y configurarlo.','Settings'=>'Configuración','Enabled'=>'Activado','Disabled'=>'Discapacitado','Configure your credentials to enable Mercado Pago payment methods.'=>'Configura tus credenciales para habilitar los métodos de pago de Mercado Pago.','The checkout is'=>'El proceso de pago es','enabled'=>'activado','disabled'=>'discapacitado','Currency conversion is'=>'La conversión de divisas es','currency conversion (feminine)enabled'=>'activado','currency conversion (feminine)disabled'=>'discapacitado','The buyer'=>'El comprador','will be automatically redirected to the store'=>'serás redirigido automáticamente a la tienda','will not be automatically redirected to the store'=>'no se le redirigirá automáticamente a la tienda','Pending payments'=>'Pagos pendientes','will be automatically declined'=>'será rechazada automáticamente','will not be automatically declined'=>'no se rechazará automáticamente','Your clients finalize their payments in Mercado Pago.'=>'Tus clientes completan sus pagos en Mercado Pago.','Mercado Pago - Checkout Pro'=>'Mercado Pago - Checkout Pro','Checkout Pro'=>'Checkout Pro','With Checkout Pro you sell with all the safety inside Mercado Pago environment.'=>'Con Checkout Pro vendes con total seguridad dentro del entorno de Mercado Pago.','Mercado Pago plugin general settings'=>'Configuración general del complemento de Mercado Pago','Set the deadlines and fees, test your store or access the Plugin manual.'=>'Establece los plazos y las tarifas, prueba tu tienda o consulta el manual del plugin.','Go to Settings'=>'Ir a «Configuración»','Enable the checkout'=>'Activar el proceso de pago','By disabling it, you will disable all payments from Mercado Pago Checkout at Mercado Pago website by redirect.'=>'Al desactivarlo, desactivarás todos los pagos realizados a través de Mercado Pago Checkout en la página web de Mercado Pago mediante redireccionamiento.','Title in the store Checkout'=>'Título en la tienda. Finalizar compra','Change the display text in Checkout, maximum characters: 85'=>'Modificar el texto que aparece en la página de pago; número máximo de caracteres: 85','The text inserted here will not be translated to other languages'=>'El texto que se inserte aquí no se traducirá a otros idiomas','Convert Currency'=>'Convertir moneda','Activate this option so that the value of the currency set in WooCommerce is compatible with the value of the currency you use in Mercado Pago.'=>'Activa esta opción para que el valor de la moneda configurada en WooCommerce sea compatible con el valor de la moneda que utilizas en Mercado Pago.','Choose the payment methods you accept in your store'=>'Elige los métodos de pago que aceptas en tu tienda','Enable the payment methods available to your clients.'=>'Activa los métodos de pago disponibles para tus clientes.','Credit Cards'=>'Tarjetas de crédito','Debit Cards'=>'Tarjetas de débito','Other Payment Methods'=>'Otras formas de pago','Maximum number of installments'=>'Número máximo de cuotas','What is the maximum quota with which a customer can buy?'=>'¿Cuál es la cantidad máxima que puede comprar un cliente?','1 installment'=>'1 cuota','2 installments'=>'2 plazos','3 installments'=>'3 plazos','4 installments'=>'4 plazos','5 installments'=>'5 plazos','6 installments'=>'6 cuotas','10 installments'=>'10 cuotas','12 installments'=>'12 cuotas','15 installments'=>'15 cuotas','18 installments'=>'18 cuotas','24 installments'=>'24 cuotas','Advanced settings'=>'Configuración avanzada','Edit these advanced fields only when you want to modify the preset values.'=>'Modifica estos campos avanzados solo cuando quieras cambiar los valores predeterminados.','Payment experience'=>'Experiencia de pago','Define what payment experience your customers will have, whether inside or outside your store.'=>'Define qué experiencia de pago tendrán tus clientes, tanto dentro como fuera de tu tienda.','Redirect'=>'Redirigir','Modal'=>'Modal','Return to the store'=>'Volver a la tienda','Do you want your customer to automatically return to the store after payment?'=>'¿Quieres que tu cliente vuelva automáticamente a la tienda tras realizar el pago?','Success URL'=>'URL de éxito','Choose the URL that we will show your customers when they finish their purchase.'=>'Elige la URL que mostraremos a tus clientes cuando finalicen su compra.','Payment URL rejected'=>'URL de pago rechazada','Choose the URL that we will show to your customers when we refuse their purchase. Make sure it includes a message appropriate to the situation and give them useful information so they can solve it.'=>'Elige la URL que mostraremos a tus clientes cuando rechacemos su compra. Asegúrate de que incluya un mensaje adecuado a la situación y de que les proporcione información útil para que puedan resolver el problema.','Payment URL pending'=>'URL de pago pendiente','Choose the URL that we will show to your customers when they have a payment pending approval.'=>'Elige la URL que mostraremos a tus clientes cuando tengan un pago pendiente de aprobación.','Automatic decline of payments without instant approval'=>'Rechazo automático de los pagos sin aprobación inmediata','Enable it if you want to automatically decline payments that are not instantly approved by banks or other institutions.'=>'Actívalo si quieres rechazar automáticamente los pagos que no sean aprobados al instante por los bancos u otras entidades.','Debit, Credit and Invoice in Mercado Pago environment.'=>'Débito, crédito y factura en el entorno de Mercado Pago.','Discount in Mercado Pago Checkouts'=>'Descuento en los pagos a través de Mercado Pago','Choose a percentage value that you want to discount your customers for paying with Mercado Pago.'=>'Elige el porcentaje de descuento que quieras aplicar a tus clientes por pagar con Mercado Pago.','Activate and show this information on Mercado Pago Checkout'=>'Activar y mostrar esta información en el proceso de pago de Mercado Pago','Commission in Mercado Pago Checkouts'=>'Comisión en los procesos de pago de Mercado Pago','Choose an additional percentage value that you want to charge as commission to your customers for paying with Mercado Pago.'=>'Elige el porcentaje adicional que deseas cobrar como comisión a tus clientes por pagar con Mercado Pago.','This seems to be an invalid URL'=>'Parece que esta URL no es válida.','“Installments without cards through Mercado Pago” is'=>'«Pagos a plazos sin tarjeta a través de Mercado Pago» es','“Up to 12 installments without cards through Mercado Pago” is'=>'«Hasta 12 cuotas sin tarjeta a través de Mercado Pago» es','Payments without a Mercado Pago card'=>'Pagos sin tarjeta de Mercado Pago','Your customers finish their payments on Mercado Pago with a credit line.'=>'Tus clientes completan sus pagos en Mercado Pago mediante una línea de crédito.','Mercado Pago - Checkout Pro Pagos sin Tarjeta'=>'Mercado Pago - Checkout Pro: pagos sin tarjeta','Up to 12 installments without cards through Mercado Pago'=>'Hasta 12 cuotas sin tarjeta a través de Mercado Pago','With this alternative, you’ll be able to sell in installments without cards and receive the money immediately with the same fees as with credit cards. Your sales are protected and guaranteed by Mercado Pago.'=>'Con esta alternativa, podrás vender a plazos sin necesidad de tarjetas y recibir el dinero al instante, con las mismas comisiones que con las tarjetas de crédito. Tus ventas están protegidas y garantizadas por Mercado Pago.','Activate the installments without cards in the checkout'=>'Activa la opción de pago a plazos sin tarjeta en la caja','Activate this feature to reach more buyers. It will be available in your store\'s checkout.'=>'Activa esta función para llegar a más compradores. Estará disponible en la página de pago de tu tienda.','Checkout visualization'=>'Visualización del proceso de pago','Check below how this feature will be displayed to your customers:'=>'A continuación puedes ver cómo se mostrará esta función a tus clientes:','Checkout Preview'=>'Vista 